  1→import { afterAll, beforeAll, describe, expect, it } from "bun:test";
  2→import { randomUUID } from "node:crypto";
  3→import { readFileSync } from "node:fs";
  4→import { join } from "node:path";
  5→import { RecordId, Surreal } from "surrealdb";
  6→import { createOpenRouter } from "@openrouter/ai-sdk-provider";
  7→import { createCreateWorkItemTool } from "../../app/src/server/chat/tools/create-work-item";
  8→
  9→const openrouter = createOpenRouter({ apiKey: process.env.OPENROUTER_API_KEY! });
 10→const embeddingModel = openrouter.textEmbeddingModel(process.env.OPENROUTER_EMBEDDING_MODEL!);
 11→const embeddingDimension = Number(process.env.EMBEDDING_DIMENSION ?? "1536");
 12→
 13→const surrealUrl = process.env.SURREAL_URL ?? "ws://127.0.0.1:8000/rpc";
 14→const surrealUsername = process.env.SURREAL_USERNAME ?? "root";
 15→const surrealPassword = process.env.SURREAL_PASSWORD ?? "root";
 16→
 17→let surreal: Surreal;
 18→let namespace: string;
 19→let database: string;
 20→let workspaceRecord: RecordId<"workspace", string>;
 21→let conversationRecord: RecordId<"conversation", string>;
 22→let personRecord: RecordId<"person", string>;
 23→let identityRecord: RecordId<"identity", string>;
 24→let messageRecord: RecordId<"message", string>;
 25→
 26→beforeAll(async () => {
 27→  const runId = `${Date.now()}_${Math.floor(Math.random() * 100000)}`;
 28→  namespace = `smoke_cwi_edge_${runId}`;
 29→  database = `cwi_edge_${Math.floor(Math.random() * 100000)}`;
 30→
 31→  surreal = new Surreal();
 32→  await surreal.connect(surrealUrl);
 33→  await surreal.signin({ username: surrealUsername, password: surrealPassword });
 34→  await surreal.query(`DEFINE NAMESPACE ${namespace};`);
 35→  await surreal.use({ namespace });
 36→  await surreal.query(`DEFINE DATABASE ${database};`);
 37→  await surreal.use({ namespace, database });
 38→
 39→  const schemaSql = readFileSync(join(process.cwd(), "schema", "surreal-schema.surql"), "utf8");
 40→  await surreal.query(schemaSql);
 41→
 42→  const now = new Date();
 43→
 44→  workspaceRecord = new RecordId("workspace", randomUUID());
 45→  await surreal.create(workspaceRecord).content({
 46→    name: "Edge Test Workspace",
 47→    status: "active",
 48→    onboarding_complete: true,
 49→    onboarding_turn_count: 0,
 50→    onboarding_summary_pending: false,
 51→    onboarding_started_at: now,
 52→    created_at: now,
 53→  });
 54→
 55→  conversationRecord = new RecordId("conversation", randomUUID());
 56→  await surreal.create(conversationRecord).content({
 57→    workspace: workspaceRecord,
 58→    createdAt: now,
 59→    updatedAt: now,
 60→  });
 61→
 62→  personRecord = new RecordId("person", randomUUID());
 63→  await surreal.query("CREATE $record CONTENT $content;", {
 64→    record: personRecord,
 65→    content: { name: "Test User", contact_email: "test@test.local", created_at: now, updated_at: now },
 66→  });
 67→  identityRecord = new RecordId("identity", randomUUID());
 68→  await surreal.query("CREATE $record CONTENT $content;", {
 69→    record: identityRecord,
 70→    content: { name: "Test User", type: "human", workspace: workspaceRecord, created_at: now },
 71→  });
 72→  await surreal.query("RELATE $identity->identity_person->$person SET added_at = time::now();", {
 73→    identity: identityRecord,
 74→    person: personRecord,
 75→  });
 76→  await surreal.query("RELATE $identity->member_of->$workspace SET added_at = time::now();", {
 77→    identity: identityRecord,
 78→    workspace: workspaceRecord,
 79→  });
 80→
 81→  messageRecord = new RecordId("message", randomUUID());
 82→  await surreal.query("CREATE $record CONTENT $content;", {
 83→    record: messageRecord,
 84→    content: {
 85→      conversation: conversationRecord,
 86→      role: "user",
 87→      text: "Create a project and features",
 88→      createdAt: now,
 89→    },
 90→  });
 91→}, 30_000);
 92→
 93→afterAll(async () => {
 94→  if (!surreal) return;
 95→  try {
 96→    await surreal.query(`REMOVE DATABASE ${database};`);
 97→    await surreal.query(`REMOVE NAMESPACE ${namespace};`);
 98→  } catch {}
 99→  await surreal.close().catch(() => {});
100→}, 10_000);
101→
102→// ── Helpers ──
103→
104→function makeTool() {
105→  return createCreateWorkItemTool({
106→    surreal,
107→    embeddingModel: embeddingModel as any,
108→    embeddingDimension,
109→    extractionModelId: "test",
110→    extractionModel: {} as any,
111→    extractionStoreThreshold: 0.5,
112→  });
113→}
114→
115→function makeOptions() {
116→  return {
117→    toolCallId: "call-1",
118→    messages: [],
119→    experimental_context: {
120→      actor: "pm_agent" as const,
121→      humanPresent: true,
122→      identityRecord,
123→      workspaceRecord,
124→      conversationRecord,
125→      currentMessageRecord: messageRecord,
126→      latestUserText: "Create a project and features",
127→    },
128→  } as any;
